import{_ as t,o as e,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"1984年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1984年/核心总结.md","filePath":"01_letters/1984年/核心总结.md"}'),l={name:"01_letters/1984年/核心总结.md"};function i(n,a,s,p,h,u){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="_1984年巴菲特致股东的信核心总结" tabindex="-1">1984年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1984年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1984年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1984年这封信，巴菲特讲透了<strong>回购、估值、损失准备金、分红政策</strong>四个投资核心问题，都是非常实战的干货。特别是分红政策那部分，逻辑清晰到让人叹服，值得每个公司管理层和投资者反复读。文末可下载英文原版PDF。</p><h2 id="一、关于回购-好公司回购真的给股东赚钱" tabindex="-1">一、关于回购：好公司回购真的给股东赚钱 <a class="header-anchor" href="#一、关于回购-好公司回购真的给股东赚钱" aria-label="Permalink to &quot;一、关于回购：好公司回购真的给股东赚钱&quot;">​</a></h2><p>巴菲特再次强调，当优秀公司股价远低于内在价值，回购对不卖的股东太有利了：</p><ul><li>算术上直接讲：一块钱投入买到两块钱现值，企业收购几乎做不到。</li><li>更重要的是长期心理层面：管理层愿意在低估的时候回购，说明它真的站在股东这边，不是整天想着扩张自己版图，市场会给这样的公司更高溢价。</li><li>巴菲特当然讨厌绿票讹诈回购，那就是三方得利，股东买单，我们坚决反对。</li></ul><p>我们三大重仓GEICO、华盛顿邮报、通用食品都这么干，我们拿着特别舒服。</p><h2 id="二、内布拉斯加家具城-b夫人的生意经-值得所有生意人抄作业" tabindex="-1">二、内布拉斯加家具城：B夫人的生意经，值得所有生意人抄作业 <a class="header-anchor" href="#二、内布拉斯加家具城-b夫人的生意经-值得所有生意人抄作业" aria-label="Permalink to &quot;二、内布拉斯加家具城：B夫人的生意经，值得所有生意人抄作业&quot;">​</a></h2><p>91岁B夫人，500美元起家做成美国最大单店家居城，毛利率只有Levitz一半，运营费用16.5%对35.6%，就是靠低价高效率，顾客每年省几千万，自己还能赚大钱。</p><p>她总结就是五个字：<strong>&quot;低价卖，说实话&quot;</strong>，听起来简单，做到极致就是伟大。巴菲特买的时候，不审计不盘点，直接给了5500万美元支票，B夫人说到做到，这么多年从来没让人失望过。</p><h2 id="三、关于保险损失准备金-这就是行业的-租西装-陷阱" tabindex="-1">三、关于保险损失准备金：这就是行业的&quot;租西装&quot;陷阱 <a class="header-anchor" href="#三、关于保险损失准备金-这就是行业的-租西装-陷阱" aria-label="Permalink to &quot;三、关于保险损失准备金：这就是行业的&quot;租西装&quot;陷阱&quot;">​</a></h2><p>财产意外险最大坑就是损失估计错了，很多几十年后才知道错了。巴菲特坦诚，我们这些年也一直低估损失，每年都要补，报告出来的利润总是比真实好。巴菲特讲了个笑话：&quot;你父亲去世了，你人在国外，姐姐帮你办葬礼，然后每个月给你寄15美元账单，直到一年后告诉你，租了套西装给父亲下葬，分期付款&quot;——这就是再保险行业很多公司计提准备金现状！</p><p>很多烂公司已经资不抵债了，还在拼命卖保单，什么价格都接，就为了现金流进，先把眼前过去坑填上，变成&quot;行走僵尸&quot;，整个行业被它们拖下水，好公司也没法赚钱。</p><h2 id="四、把债券当生意买-巴菲特买wppss的智慧" tabindex="-1">四、把债券当生意买：巴菲特买WPPSS的智慧 <a class="header-anchor" href="#四、把债券当生意买-巴菲特买wppss的智慧" aria-label="Permalink to &quot;四、把债券当生意买：巴菲特买WPPSS的智慧&quot;">​</a></h2><p>巴菲特买垃圾债券也不是瞎买，是把债券当成生意买：我们花1.39亿买WPPSS债券，每年税后拿2270万利息，就是16.3%收益率，你买个生意要赚这么多，谈判收购至少要2.5-3亿，我们半价就买到了，虽然有风险，期望值算下来很划算。</p><p>他说，1946年的时候，长期AAA债券才1%收益率，大家还抢着买，用生意思维一眼就看出来不能买，那就是给你1%净资产收益率，全仓买进去，一辈子都翻不了身，但是当年大家都抢着买，就是因为没有用生意思维看。</p><h2 id="五、分红政策到底怎么定-巴菲特讲得最清楚" tabindex="-1">五、分红政策到底怎么定：巴菲特讲得最清楚 <a class="header-anchor" href="#五、分红政策到底怎么定-巴菲特讲得最清楚" aria-label="Permalink to &quot;五、分红政策到底怎么定：巴菲特讲得最清楚&quot;">​</a></h2><p>巴菲特说，很多公司只说我们分40-50%，CPI涨了我们每年股息增长，从来不说为什么要这么分，其实核心逻辑很简单：</p><ol><li><p><strong>不是所有盈利都一样</strong>：通胀下很多企业赚的钱都是&quot;受限盈利&quot;，必须再投进去才能维持规模，不投就竞争力下降，这些盈利虽然记在利润表，其实没法分给你，分了企业就垮了。</p></li><li><p><strong>不受限盈利才是你能分的</strong>：到底分不分，就看一条：<strong>留存一块钱，能不能赚到至少一块钱市值</strong>。举个例子：如果市场无风险利率是15%，你留存一块钱只能赚10%，那你就应该分掉，让股东自己去买15%的，你拿着干嘛？如果留存一块钱能赚超过市场要求回报率，就应该留下来。</p></li><li><p>很多公司经理在这一点上完全搞反了：子公司都懂这个道理，低回报子公司分出来给高回报子公司，母公司自己却把低回报盈利留下来，不分给股东让股东自己投更好的，这太荒谬了。</p></li><li><p>伯克希尔历史上，我们留存一块钱总是能创造超过一块钱市值，所以我们一直不分，未来只要还能做到，我们就继续不分，什么时候做不到了，我们就分。</p></li></ol><h2 id="六、核心启示" tabindex="-1">六、核心启示 <a class="header-anchor" href="#六、核心启示" aria-label="Permalink to &quot;六、核心启示&quot;">​</a></h2><ol><li>回购不回购，核心就是看价格，低估买真的帮股东赚钱，高估买就是毁灭价值。</li><li>伟大生意就是把简单事情做到极致，B夫人一句话就讲透了零售业本质。</li><li>保险业很多公司把未来损失藏起来，像分期付款租西装，投资者一定要小心。</li><li>分红不是越高越好，也不是越低越好，看留存能不能赚钱，这才是本质，巴菲特这个逻辑太通透了。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201984.pdf">巴菲特1984年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',23)])])}const q=t(l,[["render",i]]);export{c as __pageData,q as default};
